using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using ResearchAgent;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient("gpt-4o-mini-2024-07-18")
    .AsIChatClient();

var notepad = new Notepad();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic, use the web_search tool
        to find relevant information from multiple angles. Take notes on key findings
        using the add_note tool. After gathering enough information (at least 3 searches),
        use the get_notes tool to review your notes, then provide a concise summary.
        """,
    name: "ResearchAgent",
    description: "Researches topics using web search and summarizes findings.",
    tools:
    [
        AIFunctionFactory.Create(WebSearchTool.SearchAsync),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ]);

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine("=== Research Summary ===\n");

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant && message.Text is { Length: > 0 } text)
    {
        Console.WriteLine(text);
    }
}

return 0;

