using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;

namespace ResearchAgent;

internal static class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(30),
    };

    [Description("Searches the web for information on a query and returns a summary of the top results.")]
    public static async Task<string> SearchAsync(
        [Description("The search query to look up on the web.")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            Console.WriteLine($"  🔍 Searching: {query}");

            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1&no_html=1";

            var json = await s_httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

            var results = new List<string>();

            if (json.TryGetProperty("AbstractText", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
            {
                var source = json.TryGetProperty("AbstractSource", out var src) ? src.GetString() : "Unknown";
                results.Add($"[{source}] {abstractText}");
            }

            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                    {
                        results.Add(t);
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing the search.";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }
}

using System.ComponentModel;

namespace ResearchAgent;

internal sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note for later reference. Use this to record key findings from searches.")]
    public string AddNote(
        [Description("The note text to save.")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved.");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var lines = _notes.Select((n, i) => $"[{i + 1}] {n}");
        return string.Join("\n", lines);
    }
}

